import { Injectable, inject, signal, computed, effect } from '@angular/core';
import { AuthDataService } from './auth-data.service';
import { AccountsService } from '../../api/api/accounts.service';
import { firstValueFrom } from 'rxjs';
import { UserRoleListItem, UserRoleResponse } from '../../api/model/models';
import { isDefined, isNullOrUndefined } from '../../shared/utils';
import { environment } from '../../../environments/environment';

export interface QAPersona {
  id: string;
  name: string;
  permissions: string[];
  ownerId: string;
  ownerType: string | null;
}

/**
 * QA Tools Service
 *
 * Provides dynamic role-based permission simulation for QA testing.
 * Fetches actual backend roles and extracts permissions from legacyRights.
 */
@Injectable({ providedIn: 'root' })
export class QAToolsService {
  private readonly authData = inject(AuthDataService);
  private readonly accountsService = inject(AccountsService);

  private readonly PERSONA_STORAGE_KEY = 'cv_qa_test_persona';

  /** Signal indicating if test mode is active */
  readonly testMode = signal<boolean>(false);

  /** Signal for the currently active test persona */
  readonly activePersona = signal<QAPersona | null>(null);

  /** List of available backend roles for the current owner */
  readonly availableRoles = signal<UserRoleListItem[]>([]);

  /** Loading state for role fetching */
  readonly isLoadingRoles = signal<boolean>(false);

  /** Set of manually toggled permissions */
  readonly manualOverrides = signal<Set<string>>(new Set());

  /** Display name for the active persona */
  readonly activeProfileName = computed(
    () => this.activePersona()?.name ?? 'Real User',
  );

  constructor() {
    // Only restore QA state in allowed environments/roles
    if (this.isQAToolsAvailable()) {
      this.restoreFromStorage();
    } else {
      // Clear any stale QA data in production
      localStorage.removeItem(this.PERSONA_STORAGE_KEY);
    }

    // Re-apply overrides if the persona or manual toggles change
    effect(() => {
      // Extra safety: only apply overrides if QA tools are available
      if (!this.isQAToolsAvailable()) {
        this.authData.resetOverrides();
        return;
      }

      const persona = this.activePersona();
      const manual = this.manualOverrides();

      if (this.testMode()) {
        const merged = new Set<string>(persona?.permissions ?? []);
        manual.forEach((p) => merged.add(p));

        const owner = persona
          ? { id: persona.ownerId, type: persona.ownerType }
          : undefined;
        this.authData.overridePermissions([...merged], owner);
      } else {
        this.authData.resetOverrides();
      }
    });
  }

  /**
   * Check if QA tools should be available
   */
  isQAToolsAvailable(): boolean {
    return !environment.production;
  }

  /**
   * Fetches all available roles for the current user's owner.
   * Uses the AccountsService as instructed.
   */
  async loadAvailableRoles(): Promise<void> {
    const ownerId = this.authData.getUserOwnerId();
    const ownerType = this.authData.getUserOwnerType();

    if (
      ownerId === null ||
      ownerId === undefined ||
      ownerType === null ||
      ownerType === undefined
    )
      return;

    this.isLoadingRoles.set(true);
    try {
      const response = await firstValueFrom(
        this.accountsService.listUserRoles(ownerId),
      );
      this.availableRoles.set(response.items ?? []);
    } catch (error) {
      console.error('QA Tools: Failed to load available roles:', error);
    } finally {
      this.isLoadingRoles.set(false);
    }
  }

  /**
   * Applies a specific role as a simulation persona.
   * Fetches full role details and extracts permissions from legacyRights.
   *
   * @remarks
   * - System role (id = 00000000-0000-0000-0000-000000000000) gets 'system:all'
   * - Roles with no legacyRights defined get empty permissions (nothing accessible)
   */
  async applyRole(roleId: string): Promise<void> {
    const roleListItem = this.availableRoles().find((r) => r.id === roleId);
    if (!roleListItem) return;

    try {
      // Fetch full role details to get legacyRights
      const fullRole: UserRoleResponse = await firstValueFrom(
        this.accountsService.getUserRole(roleId),
      );

      // System role gets all permissions
      const isSystemRole = roleId === '00000000-0000-0000-0000-000000000000';
      const permissions = isSystemRole
        ? ['system:all']
        : this.extractPermissionsFromLegacyRights(fullRole.legacyRights);

      const persona: QAPersona = {
        id: roleId,
        name: roleListItem.name ?? roleId,
        permissions: permissions,
        ownerId: roleListItem.owner.id,
        ownerType: roleListItem.owner.type ?? null,
      };

      this.activePersona.set(persona);
      this.testMode.set(true);
      this.manualOverrides.set(new Set()); // Clear overrides when applying new role
      this.saveToStorage(persona);
    } catch (error) {
      console.error('QA Tools: Failed to apply dynamic role:', error);
    }
  }

  /**
   * Resets permissions to the actual user permissions.
   */
  resetPermissions(): void {
    this.testMode.set(false);
    this.activePersona.set(null);
    this.manualOverrides.set(new Set());
    localStorage.removeItem(this.PERSONA_STORAGE_KEY);
  }

  /**
   * Check if a specific permission is manually enabled
   */
  isPermissionEnabled(permission: string): boolean {
    return this.authData.userPermissions().includes(permission);
  }

  /**
   * Toggle a manual permission override
   */
  setPermissionOverride(permission: string, enabled: boolean): void {
    const current = new Set(this.manualOverrides());
    if (enabled) {
      current.add(permission);
    } else {
      current.delete(permission);

      // Also remove from persona if it was there (making it truly 'off')
      const persona = this.activePersona();
      if (isDefined(persona?.permissions.includes(permission))) {
        const newPersonaPerms = persona.permissions.filter(
          (p) => p !== permission,
        );
        this.activePersona.set({ ...persona, permissions: newPersonaPerms });
      }
    }

    this.manualOverrides.set(current);
    if (!this.testMode()) {
      this.testMode.set(true);
    }
  }

  /**
   * Internal permission extraction logic, mirroring AuthDataService normalization.
   */
  private extractPermissionsFromLegacyRights(
    legacyRights: Record<string, string[]> | undefined,
  ): string[] {
    if (isNullOrUndefined(legacyRights)) return [];

    const permissions: string[] = [];
    for (const feature in legacyRights) {
      if (Object.hasOwn(legacyRights, feature)) {
        const actions = legacyRights[feature];
        if (Array.isArray(actions)) {
          const normalizedFeature = this.normalizeResourceName(feature);
          for (const action of actions) {
            permissions.push(`${normalizedFeature}:${action}`);
          }
        }
      }
    }
    // Deduplicate and ensure system:all is handled if needed
    return [...new Set(permissions)];
  }

  /**
   * Mirrors AuthDataService.normalizeResourceName for consistency.
   */
  private normalizeResourceName(resource: string): string {
    const normalized = resource.toLowerCase().replaceAll('-', '');
    const pluralMap: Record<string, string> = {
      vendors: 'vendor',
      clients: 'client',
      users: 'user',
      userroles: 'userrole',
      themes: 'theme',
      mapsets: 'mapset',
      assets: 'asset',
      devices: 'device',
      simcards: 'simcard',
      zones: 'zone',
      alerts: 'alert',
    };
    return pluralMap[normalized] ?? normalized;
  }

  private saveToStorage(persona: QAPersona): void {
    localStorage.setItem(this.PERSONA_STORAGE_KEY, JSON.stringify(persona));
  }

  private restoreFromStorage(): void {
    const stored = localStorage.getItem(this.PERSONA_STORAGE_KEY);
    if (stored !== null && stored !== undefined) {
      try {
        const persona: QAPersona = JSON.parse(stored);
        this.activePersona.set(persona);
        this.testMode.set(true);
      } catch (err) {
        console.error('QA Tools: Error restoring persona from storage:', err);
        localStorage.removeItem(this.PERSONA_STORAGE_KEY);
      }
    }
  }
}
